import React, { useState, useEffect, useRef } from 'react';
import { useLocation, useParams, useNavigate } from 'react-router-dom';

const StudySession = ({ markDayComplete }) => {
  const { day } = useParams();
  const { state } = useLocation();
  const navigate = useNavigate();

  const [timeLeft, setTimeLeft] = useState(2700); // 45 Minutes
  const [isActive, setIsActive] = useState(false);
  const [sessionFinished, setSessionFinished] = useState(false);
  const [tabWarning, setTabWarning] = useState(false);
  const [userAnswer, setUserAnswer] = useState('');
  
  const videoRef = useRef(null);
  const streamRef = useRef(null); // Ref to store the stream for strict cleanup

  // 1. CAMERA LOGIC: Start camera and handle cleanup
  useEffect(() => {
    async function startCamera() {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ video: true });
        streamRef.current = stream; // Store stream in a ref
        if (videoRef.current) {
          videoRef.current.srcObject = stream;
        }
      } catch (err) {
        alert("CRITICAL: Camera access is required for proctoring. Please allow camera access to study.");
      }
    }

    startCamera();

    // CLEANUP: This runs when you leave the page
    return () => {
      if (streamRef.current) {
        const tracks = streamRef.current.getTracks();
        tracks.forEach(track => track.stop()); // Physically turns off the camera
        streamRef.current = null;
      }
      if (videoRef.current) {
        videoRef.current.srcObject = null; // Clears the video element
      }
      console.log("Camera access blocked and tracks stopped.");
    };
  }, []);

  // 2. TAB VISIBILITY: Stop timer if student leaves tab
  useEffect(() => {
    const handleVisibilityChange = () => {
      if (document.hidden) {
        setIsActive(false);
        setTabWarning(true);
      } else {
        setTabWarning(false);
      }
    };

    document.addEventListener("visibilitychange", handleVisibilityChange);
    return () => document.removeEventListener("visibilitychange", handleVisibilityChange);
  }, []);

  // 3. TIMER LOGIC
  useEffect(() => {
    let interval = null;
    if (isActive && timeLeft > 0) {
      interval = setInterval(() => setTimeLeft(prev => prev - 1), 1000);
    } else if (timeLeft === 0) {
      setSessionFinished(true);
      setIsActive(false);
    }
    return () => clearInterval(interval);
  }, [isActive, timeLeft]);

  const formatTime = (seconds) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}m ${secs < 10 ? '0' : ''}${secs}s`;
  };

  const handleFinalSubmit = () => {
    if (userAnswer.length < 30) {
      alert("Please provide a more detailed summary of your 45-minute practice.");
      return;
    }
    markDayComplete(day);
    navigate('/dashboard');
  };

  return (
    <div style={{ padding: '20px', textAlign: 'center', backgroundColor: '#f8f9fa', minHeight: '100vh' }}>
      <div style={{ maxWidth: '750px', margin: '0 auto', background: 'white', padding: '30px', borderRadius: '20px', boxShadow: '0 10px 40px rgba(0,0,0,0.1)' }}>
        
        <h2 style={{ color: '#2c3e50', marginBottom: '10px' }}>Study Session: Day {day}</h2>
        <p style={{ color: '#3498db', fontWeight: 'bold' }}>Topic: {state?.topic || "Loading..."}</p>

        {/* PROCTOR VIDEO PANEL */}
        <div style={{ position: 'relative', width: '400px', height: '300px', margin: '20px auto', backgroundColor: '#2c3e50', borderRadius: '15px', overflow: 'hidden', border: '5px solid #ecf0f1' }}>
          <video 
            ref={videoRef} 
            autoPlay 
            playsInline 
            muted 
            style={{ width: '100%', height: '100%', objectFit: 'cover', transform: 'scaleX(-1)' }} 
          />
          {!isActive && !sessionFinished && (
            <div style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', background: 'rgba(0,0,0,0.5)', color: 'white', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '20px' }}>
              ⏸ Session Paused
            </div>
          )}
        </div>

        {/* WARNING MESSAGE */}
        {tabWarning && (
          <div style={{ color: 'white', background: '#e74c3c', padding: '10px', borderRadius: '8px', marginBottom: '15px', fontWeight: 'bold' }}>
            🚫 Tab Switch Detected! Timer has been paused. Stay focused.
          </div>
        )}

        <div style={{ fontSize: '80px', fontWeight: '900', color: timeLeft === 0 ? '#27ae60' : '#2c3e50', margin: '20px 0' }}>
          {formatTime(timeLeft)}
        </div>

        {!sessionFinished ? (
          <div>
            <p style={{ color: '#7f8c8d', fontStyle: 'italic' }}>Note: You cannot mark this day as complete until the timer hits 00:00.</p>
            <button 
              onClick={() => setIsActive(!isActive)}
              style={{ 
                padding: '15px 50px', 
                fontSize: '20px', 
                background: isActive ? '#f39c12' : '#2ecc71', 
                color: 'white', 
                border: 'none', 
                borderRadius: '50px', 
                cursor: 'pointer',
                transition: '0.3s'
              }}
            >
              {isActive ? 'Pause Study' : 'Start Focus Session'}
            </button>
          </div>
        ) : (
          <div style={{ marginTop: '20px', textAlign: 'left', borderTop: '2px solid #eee', paddingTop: '20px' }}>
            <h3 style={{ color: '#27ae60' }}>🎉 Focus Session Complete!</h3>
            <p>Prove your learning: What was the most important thing you practiced in the last 45 minutes?</p>
            <textarea 
              value={userAnswer}
              onChange={(e) => setUserAnswer(e.target.value)}
              style={{ width: '100%', height: '100px', padding: '10px', borderRadius: '10px', border: '1px solid #ccc' }}
              placeholder="Enter your detailed summary..."
            />
            <button 
              onClick={handleFinalSubmit}
              style={{ width: '100%', marginTop: '15px', padding: '15px', background: '#2c3e50', color: 'white', borderRadius: '10px', cursor: 'pointer', fontWeight: 'bold' }}
            >
              Verify Knowledge & Finish Day {day}
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default StudySession;
